function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use a max-heap to prioritize paths with higher minimum edge cost
    // We'll use a priority queue where each element is [minEdgeCost, currentCost, currentNode]
    // We'll also track the maximum minimum edge cost found
    let maxMinEdge = -1;
    const visited: Set<number> = new Set();

    // Use a priority queue (max-heap) for Dijkstra-like approach
    // We'll use a max-heap implemented with a min-heap by storing negative values
    const pq: [number, number, number][] = [];
    pq.push([0, 0, 0]); // [minEdgeCost, currentCost, currentNode]

    while (pq.length > 0) {
        // Pop the element with the highest minEdgeCost
        pq.sort((a, b) => b[0] - a[0]);
        const [minEdge, currentCost, node] = pq.shift()!;

        // If we've already visited this node with a higher or equal minEdge, skip
        if (visited.has(node)) {
            continue;
        }
        visited.add(node);

        // If we've reached the destination node, update the maxMinEdge
        if (node === n - 1) {
            maxMinEdge = Math.max(maxMinEdge, minEdge);
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const [neighbor, cost] of graph.get(node)!.entries()) {
                // Check if the neighbor is online
                if (!online[neighbor]) {
                    continue;
                }

                // Calculate the new minEdge and currentCost
                const newMinEdge = Math.min(minEdge, cost);
                const newCurrentCost = currentCost + cost;

                // If the new current cost is within k, add to the priority queue
                if (newCurrentCost <= k) {
                    pq.push([newMinEdge, newCurrentCost, neighbor]);
                }
            }
        }
    }

    return maxMinEdge;
}

